1	import {
2	  dehydrate,
3	  hydrate,
4	  type DehydratedState,
5	  type Query,
6	  type QueryClient,
7	  type QueryKey,
8	} from '@tanstack/react-query';
9	
10	const DB_NAME = 'fitcommerce-offline-cache';
11	const STORE_NAME = 'app-state';
12	const QUERY_CACHE_KEY = 'react-query';
13	const QUERY_CACHE_VERSION = 1;
14	
15	const OFFLINE_QUERY_ROOTS = new Set([
16	  'dashboard',
17	  'items',
18	  'campaigns',
19	  'orders',
20	  'inventory',
21	  'purchase-orders',
22	  'suppliers',
23	  'variances',
24	  'reports',
25	  'exports',
26	  'warehouse-bins',
27	  'locations',
28	  'members',
29	  'coaches',
30	  'landed-costs',
31	]);
32	
33	interface PersistedQuerySnapshot {
34	  version: number;
35	  updatedAt: number;
36	  state: DehydratedState;
37	}
38	
39	function openDatabase(): Promise<IDBDatabase> {
40	  return new Promise((resolve, reject) => {
41	    const request = window.indexedDB.open(DB_NAME, 1);
42	    request.onerror = () => reject(request.error);
43	    request.onupgradeneeded = () => {
44	      const database = request.result;
45	      if (!database.objectStoreNames.contains(STORE_NAME)) {
46	        database.createObjectStore(STORE_NAME);
47	      }
48	    };
49	    request.onsuccess = () => resolve(request.result);
50	  });
51	}
52	
53	async function readStoreValue<T>(key: string): Promise<T | null> {
54	  const database = await openDatabase();
55	  return new Promise((resolve, reject) => {
56	    const transaction = database.transaction(STORE_NAME, 'readonly');
57	    const store = transaction.objectStore(STORE_NAME);
58	    const request = store.get(key);
59	    request.onerror = () => reject(request.error);
60	    request.onsuccess = () => resolve((request.result as T | undefined) ?? null);
61	    transaction.oncomplete = () => database.close();
62	    transaction.onerror = () => reject(transaction.error);
63	  });
64	}
65	
66	async function writeStoreValue<T>(key: string, value: T): Promise<void> {
67	  const database = await openDatabase();
68	  return new Promise((resolve, reject) => {
69	    const transaction = database.transaction(STORE_NAME, 'readwrite');
70	    const store = transaction.objectStore(STORE_NAME);
71	    const request = store.put(value, key);
72	    request.onerror = () => reject(request.error);
73	    transaction.oncomplete = () => {
74	      database.close();
75	      resolve();
76	    };
77	    transaction.onerror = () => reject(transaction.error);
78	  });
79	}
80	
81	function isOfflineCacheableQuery(query: Query): boolean {
82	  return query.state.status === 'success' && isOfflineCacheableQueryKey(query.queryKey);
83	}
84	
85	export function isOfflineCacheableQueryKey(queryKey: QueryKey): boolean {
86	  const root = Array.isArray(queryKey) ? queryKey[0] : undefined;
87	  return typeof root === 'string' && OFFLINE_QUERY_ROOTS.has(root);
88	}
89	
90	export async function loadPersistedQuerySnapshot(): Promise<PersistedQuerySnapshot | null> {
91	  if (typeof window === 'undefined' || !('indexedDB' in window)) {
92	    return null;
93	  }
94	  const snapshot = await readStoreValue<PersistedQuerySnapshot>(QUERY_CACHE_KEY);
95	  if (!snapshot || snapshot.version !== QUERY_CACHE_VERSION) {
96	    return null;
97	  }
98	  return snapshot;
99	}
100	
101	export function hydrateOfflineQueryCache(queryClient: QueryClient, snapshot: PersistedQuerySnapshot | null): void {
102	  if (!snapshot) {
103	    return;
104	  }
105	  hydrate(queryClient, snapshot.state);
106	}
107	
108	export async function persistOfflineQueryCache(queryClient: QueryClient): Promise<number | null> {
109	  if (typeof window === 'undefined' || !('indexedDB' in window)) {
110	    return null;
111	  }
112	
113	  const snapshot: PersistedQuerySnapshot = {
114	    version: QUERY_CACHE_VERSION,
115	    updatedAt: Date.now(),
116	    state: dehydrate(queryClient, {
117	      shouldDehydrateQuery: isOfflineCacheableQuery,
118	    }),
119	  };
120	
121	  await writeStoreValue(QUERY_CACHE_KEY, snapshot);
122	  return snapshot.updatedAt;
123	}
