1	import { useEffect, useRef, useState, type ReactNode } from 'react';
2	import { QueryClient, QueryClientProvider } from '@tanstack/react-query';
3	import { ThemeProvider } from '@mui/material/styles';
4	import CssBaseline from '@mui/material/CssBaseline';
5	import theme from '@/app/theme';
6	import { AuthProvider } from '@/lib/auth';
7	import { OfflineStatusProvider } from '@/lib/offline';
8	import {
9	  hydrateOfflineQueryCache,
10	  loadPersistedQuerySnapshot,
11	  persistOfflineQueryCache,
12	} from '@/lib/offline-cache';
13	import { NotificationsProvider } from '@/lib/notifications';
14	import { ErrorBoundary } from '@/components/ErrorBoundary';
15	
16	const queryClient = new QueryClient({
17	  defaultOptions: {
18	    queries: {
19	      staleTime: 30 * 1000,
20	      refetchOnWindowFocus: false,
21	      retry: 1,
22	      refetchOnReconnect: false,
23	    },
24	    mutations: {
25	      retry: 0,
26	    },
27	  },
28	});
29	
30	interface ProvidersProps {
31	  children: ReactNode;
32	}
33	
34	export default function Providers({ children }: ProvidersProps) {
35	  const [isHydrated, setIsHydrated] = useState(false);
36	  const [lastSyncAt, setLastSyncAt] = useState<number | null>(null);
37	  const persistTimerRef = useRef<number | null>(null);
38	
39	  useEffect(() => {
40	    let active = true;
41	    let unsubscribe: (() => void) | undefined;
42	
43	    const schedulePersist = () => {
44	      if (persistTimerRef.current !== null) {
45	        window.clearTimeout(persistTimerRef.current);
46	      }
47	      persistTimerRef.current = window.setTimeout(async () => {
48	        try {
49	          const persistedAt = await persistOfflineQueryCache(queryClient);
50	          if (active && persistedAt) {
51	            setLastSyncAt(persistedAt);
52	          }
53	        } catch {
54	          // Offline persistence is best-effort and should never block app use.
55	        }
56	      }, 250);
57	    };
58	
59	    (async () => {
60	      try {
61	        const snapshot = await loadPersistedQuerySnapshot();
62	        if (active) {
63	          hydrateOfflineQueryCache(queryClient, snapshot);
64	          setLastSyncAt(snapshot?.updatedAt ?? null);
65	        }
66	      } catch {
67	        // If persistence cannot be read we fall back to the live API path.
68	      } finally {
69	        if (active) {
70	          unsubscribe = queryClient.getQueryCache().subscribe(() => {
71	            schedulePersist();
72	          });
73	          setIsHydrated(true);
74	        }
75	      }
76	    })();
77	
78	    return () => {
79	      active = false;
80	      unsubscribe?.();
81	      if (persistTimerRef.current !== null) {
82	        window.clearTimeout(persistTimerRef.current);
83	      }
84	    };
85	  }, []);
86	
87	  return (
88	    <QueryClientProvider client={queryClient}>
89	      <ThemeProvider theme={theme}>
90	        <CssBaseline />
91	        {isHydrated ? (
92	          <OfflineStatusProvider lastSyncAt={lastSyncAt}>
93	            <AuthProvider>
94	              <NotificationsProvider>
95	                <ErrorBoundary>
96	                  {children}
97	                </ErrorBoundary>
98	              </NotificationsProvider>
99	            </AuthProvider>
100	          </OfflineStatusProvider>
101	        ) : null}
102	      </ThemeProvider>
103	    </QueryClientProvider>
104	  );
105	}
