1	const BASE_URL = import.meta.env.VITE_API_BASE_URL ?? '/api/v1';
2	
3	export interface ApiError {
4	  code: string;
5	  message: string;
6	  details?: { field?: string; message: string }[];
7	  status: number;
8	}
9	
10	function createNetworkError(): ApiError {
11	  const offline = typeof navigator !== 'undefined' && !navigator.onLine;
12	  return {
13	    code: offline ? 'NETWORK_OFFLINE' : 'NETWORK_ERROR',
14	    message: offline
15	      ? 'You are offline. Cached data remains available until you reconnect.'
16	      : 'Unable to reach the FitCommerce server.',
17	    status: 0,
18	  };
19	}
20	
21	export function isOfflineApiError(error: unknown): error is ApiError {
22	  if (!error || typeof error !== 'object') {
23	    return false;
24	  }
25	  const candidate = error as Partial<ApiError>;
26	  return candidate.status === 0 && (candidate.code === 'NETWORK_OFFLINE' || candidate.code === 'NETWORK_ERROR');
27	}
28	
29	export interface PaginatedResponse<T> {
30	  data: T[];
31	  pagination: {
32	    page: number;
33	    page_size: number;
34	    total_count: number;
35	    total_pages: number;
36	  };
37	}
38	
39	export interface ApiEnvelope<T> {
40	  data: T;
41	}
42	
43	export interface ApiMessage {
44	  message: string;
45	}
46	
47	export interface PaginationParams {
48	  page?: number;
49	  page_size?: number;
50	  sort_by?: string;
51	  sort_order?: 'asc' | 'desc';
52	}
53	
54	async function handleApiError(response: Response): Promise<never> {
55	  let errorData: { error?: { code?: string; message?: string; details?: { field?: string; message: string }[] } } = {};
56	  try {
57	    errorData = await response.json();
58	  } catch {
59	    // Response body may not be JSON
60	  }
61	
62	  const apiError: ApiError = {
63	    code: errorData.error?.code ?? 'UNKNOWN_ERROR',
64	    message: errorData.error?.message ?? `HTTP ${response.status}: ${response.statusText}`,
65	    details: errorData.error?.details,
66	    status: response.status,
67	  };
68	
69	  if (response.status === 401) {
70	    window.dispatchEvent(new CustomEvent('auth:session-expired'));
71	  }
72	
73	  throw apiError;
74	}
75	
76	async function fetchWithHandling(input: RequestInfo | URL, init: RequestInit): Promise<Response> {
77	  try {
78	    return await fetch(input, init);
79	  } catch {
80	    throw createNetworkError();
81	  }
82	}
83	
84	function buildQueryString(params?: Record<string, string | number | boolean | undefined | null>): string {
85	  if (!params) return '';
86	  const searchParams = new URLSearchParams();
87	  for (const [key, value] of Object.entries(params)) {
88	    if (value !== undefined && value !== null && value !== '') {
89	      searchParams.set(key, String(value));
90	    }
91	  }
92	  const qs = searchParams.toString();
93	  return qs ? `?${qs}` : '';
94	}
95	
96	export const apiClient = {
97	  async get<T>(
98	    path: string,
99	    params?: Record<string, string | number | boolean | undefined | null>,
100	  ): Promise<T> {
101	    const url = `${BASE_URL}${path}${buildQueryString(params)}`;
102	    const response = await fetchWithHandling(url, {
103	      method: 'GET',
104	      headers: {
105	        'Accept': 'application/json',
106	      },
107	      credentials: 'include',
108	    });
109	
110	    if (!response.ok) {
111	      await handleApiError(response);
112	    }
113	
114	    return response.json() as Promise<T>;
115	  },
116	
117	  async post<T>(path: string, body: unknown): Promise<T> {
118	    const url = `${BASE_URL}${path}`;
119	    const response = await fetchWithHandling(url, {
120	      method: 'POST',
121	      headers: {
122	        'Content-Type': 'application/json',
123	        'Accept': 'application/json',
124	      },
125	      credentials: 'include',
126	      body: JSON.stringify(body),
127	    });
128	
129	    if (!response.ok) {
130	      await handleApiError(response);
131	    }
132	
133	    if (response.status === 204) {
134	      return undefined as T;
135	    }
136	
137	    return response.json() as Promise<T>;
138	  },
139	
140	  async put<T>(path: string, body: unknown): Promise<T> {
141	    const url = `${BASE_URL}${path}`;
142	    const response = await fetchWithHandling(url, {
143	      method: 'PUT',
144	      headers: {
145	        'Content-Type': 'application/json',
146	        'Accept': 'application/json',
147	      },
148	      credentials: 'include',
149	      body: JSON.stringify(body),
150	    });
151	
152	    if (!response.ok) {
153	      await handleApiError(response);
154	    }
155	
156	    if (response.status === 204) {
157	      return undefined as T;
158	    }
159	
160	    return response.json() as Promise<T>;
161	  },
162	
163	  async delete<T>(path: string): Promise<T> {
164	    const url = `${BASE_URL}${path}`;
165	    const response = await fetchWithHandling(url, {
166	      method: 'DELETE',
167	      headers: {
168	        'Accept': 'application/json',
169	      },
170	      credentials: 'include',
171	    });
172	
173	    if (!response.ok) {
174	      await handleApiError(response);
175	    }
176	
177	    if (response.status === 204) {
178	      return undefined as T;
179	    }
180	
181	    return response.json() as Promise<T>;
182	  },
183	};
184	
185	function extractFilename(contentDisposition: string | null): string | undefined {
186	  if (!contentDisposition) {
187	    return undefined;
188	  }
189	
190	  const utf8Match = contentDisposition.match(/filename\*=UTF-8''([^;]+)/i);
191	  if (utf8Match?.[1]) {
192	    return decodeURIComponent(utf8Match[1]);
193	  }
194	
195	  const plainMatch = contentDisposition.match(/filename="?([^"]+)"?/i);
196	  return plainMatch?.[1];
197	}
198	
199	export async function downloadFile(url: string, filename?: string): Promise<string> {
200	  const fullUrl = `${BASE_URL}${url}`;
201	  const response = await fetchWithHandling(fullUrl, {
202	    method: 'GET',
203	    credentials: 'include',
204	  });
205	
206	  if (!response.ok) {
207	    await handleApiError(response);
208	  }
209	
210	  const blob = await response.blob();
211	  const resolvedFilename = filename ?? extractFilename(response.headers.get('Content-Disposition')) ?? 'download';
212	  const objectUrl = URL.createObjectURL(blob);
213	  const anchor = document.createElement('a');
214	  anchor.href = objectUrl;
215	  anchor.download = resolvedFilename;
216	  document.body.appendChild(anchor);
217	  anchor.click();
218	  document.body.removeChild(anchor);
219	  URL.revokeObjectURL(objectUrl);
220	
221	  return resolvedFilename;
222	}
