    expect(isOfflineCacheableQueryKey(['retention-policies'])).toBe(true);
  });
});

// ─── Non-cacheable roots ──────────────────────────────────────────────────────

describe('isOfflineCacheableQueryKey — non-cacheable roots', () => {
