49	export type OfflineMutationType = "create-item" | "update-item" | "run-export";
50	export type OfflineMutationStatus = "pending" | "failed";
51	
52	export interface OfflineMutationEntry {
53	  id: string;
54	  type: OfflineMutationType;
55	  payload: Record<string, unknown>;
56	  createdAt: number;
57	  status?: OfflineMutationStatus;
58	  updatedAt?: number;
59	  lastError?: string;
60	}
61	
62	interface PersistedMutationQueue {
63	  version: number;
64	  updatedAt: number;
65	  mutations: OfflineMutationEntry[];
66	}
