117	function isOfflineCacheableQuery(query: Query): boolean {
118	  return (
119	    query.state.status === "success" &&
120	    isOfflineCacheableQueryKey(query.queryKey)
121	  );
122	}
123	
124	export function isOfflineCacheableQueryKey(queryKey: QueryKey): boolean {
125	  const root = Array.isArray(queryKey) ? queryKey[0] : undefined;
126	  return typeof root === "string" && OFFLINE_QUERY_ROOTS.has(root);
127	}
