1	import type { QueryClient } from "@tanstack/react-query";
2	import { apiClient, isOfflineApiError } from "@/lib/api-client";
3	import {
4	  loadPendingOfflineMutations,
5	  markOfflineMutationFailed,
6	  removeOfflineMutation,
7	  setOfflineItemIDMapping,
8	  type OfflineMutationEntry,
9	} from "@/lib/offline-cache";
10	
11	function isBrowserOffline(): boolean {
12	  return typeof navigator !== "undefined" && !navigator.onLine;
13	}
14	
15	async function executeMutation(entry: OfflineMutationEntry): Promise<void> {
16	  switch (entry.type) {
17	    case "create-item": {
18	      const temporaryID =
19	        typeof entry.payload.__offline_temp_id === "string"
20	          ? entry.payload.__offline_temp_id
21	          : undefined;
22	      const payload = { ...entry.payload };
23	      delete payload.__offline_temp_id;
24	
25	      const response = await apiClient.post<
26	        Record<string, unknown> | { data?: Record<string, unknown> }
27	      >("/items", payload);
28	
29	      const serverID =
30	        (typeof response?.id === "string" ? response.id : undefined) ??
31	        (typeof response?.data === "object" &&
32	        response.data &&
33	        typeof (response.data as Record<string, unknown>).id === "string"
34	          ? ((response.data as Record<string, unknown>).id as string)
35	          : undefined);
36	
37	      if (temporaryID && serverID) {
38	        await setOfflineItemIDMapping(temporaryID, serverID);
39	      }
40	      return;
41	    }
42	    case "update-item": {
43	      const id = entry.payload.id;
44	      const body = entry.payload.body;
45	      if (typeof id !== "string" || !body || typeof body !== "object") {
46	        return;
47	      }
48	      await apiClient.put(`/items/${id}`, body);
49	      return;
50	    }
51	    case "run-export":
52	      await apiClient.post("/exports", entry.payload);
53	      return;
54	    default:
55	      return;
56	  }
57	}
58	
59	export async function replayOfflineMutations(
60	  queryClient: QueryClient,
61	): Promise<number> {
62	  if (isBrowserOffline()) {
63	    return 0;
64	  }
65	
66	  const queue = await loadPendingOfflineMutations();
67	  let processed = 0;
68	
69	  for (const entry of queue) {
70	    if (entry.status === "failed") {
71	      continue;
72	    }
73	
74	    try {
75	      await executeMutation(entry);
76	      await removeOfflineMutation(entry.id);
77	      processed += 1;
78	    } catch (error) {
79	      if (isOfflineApiError(error)) {
80	        break;
81	      }
82	
83	      const message =
84	        typeof error === "object" && error && "message" in error
85	          ? String((error as { message?: unknown }).message ?? "replay failed")
86	          : "replay failed";
87	      await markOfflineMutationFailed(entry.id, message);
88	    }
89	  }
90	
91	  if (processed > 0) {
92	    queryClient.invalidateQueries({ queryKey: ["items"] });
93	    queryClient.invalidateQueries({ queryKey: ["reports"] });
94	    queryClient.invalidateQueries({ queryKey: ["exports"] });
95	  }
96	
97	  return processed;
98	}
