74	function openDatabase(): Promise<IDBDatabase> {
75	  return new Promise((resolve, reject) => {
76	    const request = window.indexedDB.open(DB_NAME, 1);
77	    request.onerror = () => reject(request.error);
78	    request.onupgradeneeded = () => {
79	      const database = request.result;
80	      if (!database.objectStoreNames.contains(STORE_NAME)) {
81	        database.createObjectStore(STORE_NAME);
82	      }
83	    };
84	    request.onsuccess = () => resolve(request.result);
85	  });
86	}
