88	async function readStoreValue<T>(key: string): Promise<T | null> {
89	  const database = await openDatabase();
90	  return new Promise((resolve, reject) => {
91	    const transaction = database.transaction(STORE_NAME, "readonly");
92	    const store = transaction.objectStore(STORE_NAME);
93	    const request = store.get(key);
94	    request.onerror = () => reject(request.error);
95	    request.onsuccess = () =>
96	      resolve((request.result as T | undefined) ?? null);
97	    transaction.oncomplete = () => database.close();
98	    transaction.onerror = () => reject(transaction.error);
99	  });
100	}
101	
102	async function writeStoreValue<T>(key: string, value: T): Promise<void> {
103	  const database = await openDatabase();
104	  return new Promise((resolve, reject) => {
105	    const transaction = database.transaction(STORE_NAME, "readwrite");
106	    const store = transaction.objectStore(STORE_NAME);
107	    const request = store.put(value, key);
108	    request.onerror = () => reject(request.error);
109	    transaction.oncomplete = () => {
110	      database.close();
111	      resolve();
112	    };
113	    transaction.onerror = () => reject(transaction.error);
114	  });
115	}
116	
117	function isOfflineCacheableQuery(query: Query): boolean {
118	  return (
119	    query.state.status === "success" &&
120	    isOfflineCacheableQueryKey(query.queryKey)
121	  );
122	}
123	
124	export function isOfflineCacheableQueryKey(queryKey: QueryKey): boolean {
125	  const root = Array.isArray(queryKey) ? queryKey[0] : undefined;
126	  return typeof root === "string" && OFFLINE_QUERY_ROOTS.has(root);
127	}
128	
129	export async function loadPersistedQuerySnapshot(): Promise<PersistedQuerySnapshot | null> {
130	  if (typeof window === "undefined" || !("indexedDB" in window)) {
131	    return null;
132	  }
133	  const snapshot =
134	    await readStoreValue<PersistedQuerySnapshot>(QUERY_CACHE_KEY);
135	  if (!snapshot || snapshot.version !== QUERY_CACHE_VERSION) {
136	    return null;
137	  }
138	  return snapshot;
139	}
140	
141	export function hydrateOfflineQueryCache(
142	  queryClient: QueryClient,
143	  snapshot: PersistedQuerySnapshot | null,
144	): void {
145	  if (!snapshot) {
146	    return;
147	  }
148	  hydrate(queryClient, snapshot.state);
149	}
150	
151	export async function persistOfflineQueryCache(
152	  queryClient: QueryClient,
153	): Promise<number | null> {
154	  if (typeof window === "undefined" || !("indexedDB" in window)) {
155	    return null;
156	  }
157	
158	  const snapshot: PersistedQuerySnapshot = {
159	    version: QUERY_CACHE_VERSION,
160	    updatedAt: Date.now(),
161	    state: dehydrate(queryClient, {
162	      shouldDehydrateQuery: isOfflineCacheableQuery,
163	    }),
164	  };
165	
166	  await writeStoreValue(QUERY_CACHE_KEY, snapshot);
167	  return snapshot.updatedAt;
168	}
169	
170	export async function loadPendingOfflineMutations(): Promise<
171	  OfflineMutationEntry[]
172	> {
173	  if (typeof window === "undefined" || !("indexedDB" in window)) {
174	    return [];
175	  }
176	
177	  const persisted =
178	    await readStoreValue<PersistedMutationQueue>(MUTATION_QUEUE_KEY);
179	  if (!persisted || persisted.version !== MUTATION_QUEUE_VERSION) {
180	    return [];
181	  }
182	  return persisted.mutations;
183	}
184	
185	export async function enqueueOfflineMutation(
186	  entry: OfflineMutationEntry,
187	): Promise<void> {
188	  if (typeof window === "undefined" || !("indexedDB" in window)) {
189	    return;
190	  }
191	
192	  const existing = await loadPendingOfflineMutations();
193	  const queue: PersistedMutationQueue = {
194	    version: MUTATION_QUEUE_VERSION,
195	    updatedAt: Date.now(),
196	    mutations: [...existing, { ...entry, status: entry.status ?? "pending" }],
197	  };
198	  await writeStoreValue(MUTATION_QUEUE_KEY, queue);
199	}
200	
201	export async function markOfflineMutationFailed(
202	  id: string,
203	  message: string,
204	): Promise<void> {
205	  if (typeof window === "undefined" || !("indexedDB" in window)) {
206	    return;
207	  }
208	
209	  const existing = await loadPendingOfflineMutations();
210	  const now = Date.now();
211	  const queue: PersistedMutationQueue = {
212	    version: MUTATION_QUEUE_VERSION,
213	    updatedAt: now,
214	    mutations: existing.map((entry) => {
215	      if (entry.id !== id) {
216	        return entry;
217	      }
218	      return {
219	        ...entry,
220	        status: "failed",
221	        updatedAt: now,
222	        lastError: message,
223	      };
224	    }),
225	  };
226	  await writeStoreValue(MUTATION_QUEUE_KEY, queue);
227	}
228	
229	export async function removeOfflineMutation(id: string): Promise<void> {
230	  if (typeof window === "undefined" || !("indexedDB" in window)) {
231	    return;
232	  }
233	
234	  const existing = await loadPendingOfflineMutations();
235	  const queue: PersistedMutationQueue = {
236	    version: MUTATION_QUEUE_VERSION,
237	    updatedAt: Date.now(),
238	    mutations: existing.filter((entry) => entry.id !== id),
239	  };
240	  await writeStoreValue(MUTATION_QUEUE_KEY, queue);
241	}
242	
243	export async function setOfflineItemIDMapping(
244	  temporaryID: string,
245	  serverID: string,
246	): Promise<void> {
247	  if (typeof window === "undefined" || !("indexedDB" in window)) {
248	    return;
249	  }
250	
251	  const existing = await readStoreValue<PersistedItemIDMap>(ITEM_ID_MAP_KEY);
252	  const queue: PersistedItemIDMap = {
253	    version: 1,
254	    updatedAt: Date.now(),
255	    mappings: {
256	      ...(existing?.mappings ?? {}),
257	      [temporaryID]: serverID,
258	    },
259	  };
260	  await writeStoreValue(ITEM_ID_MAP_KEY, queue);
261	}
262	
263	export async function resolveOfflineItemID(id: string): Promise<string> {
264	  if (typeof window === "undefined" || !("indexedDB" in window)) {
265	    return id;
266	  }
267	
268	  const existing = await readStoreValue<PersistedItemIDMap>(ITEM_ID_MAP_KEY);
269	  if (!existing || existing.version !== 1) {
270	    return id;
271	  }
272	  return existing.mappings[id] ?? id;
273	}
