1	import { createContext, useContext, useState, useCallback, type ReactNode } from 'react';
2	import Snackbar from '@mui/material/Snackbar';
3	import Alert, { type AlertColor } from '@mui/material/Alert';
4	
5	interface Notification {
6	  id: number;
7	  message: string;
8	  severity: AlertColor;
9	}
10	
11	interface NotifyFn {
12	  success: (message: string) => void;
13	  error: (message: string) => void;
14	  warning: (message: string) => void;
15	  info: (message: string) => void;
16	}
17	
18	const NotifyContext = createContext<NotifyFn | null>(null);
19	
20	let nextId = 0;
21	
22	export function NotificationsProvider({ children }: { children: ReactNode }) {
23	  const [queue, setQueue] = useState<Notification[]>([]);
24	  const [current, setCurrent] = useState<Notification | null>(null);
25	  const [open, setOpen] = useState(false);
26	
27	  const enqueue = useCallback((message: string, severity: AlertColor) => {
28	    const notification: Notification = { id: ++nextId, message, severity };
29	    setQueue(prev => {
30	      if (prev.length === 0 && !open) {
31	        setCurrent(notification);
32	        setOpen(true);
33	        return [];
34	      }
35	      return [...prev, notification];
36	    });
37	  }, [open]);
38	
39	  const handleClose = (_: unknown, reason?: string) => {
40	    if (reason === 'clickaway') return;
41	    setOpen(false);
42	  };
43	
44	  const handleExited = () => {
45	    if (queue.length > 0) {
46	      const [next, ...rest] = queue;
47	      setQueue(rest);
48	      setCurrent(next);
49	      setOpen(true);
50	    } else {
51	      setCurrent(null);
52	    }
53	  };
54	
55	  const notify: NotifyFn = {
56	    success: msg => enqueue(msg, 'success'),
57	    error: msg => enqueue(msg, 'error'),
58	    warning: msg => enqueue(msg, 'warning'),
59	    info: msg => enqueue(msg, 'info'),
60	  };
61	
62	  return (
63	    <NotifyContext.Provider value={notify}>
64	      {children}
65	      <Snackbar
66	        open={open}
67	        autoHideDuration={5000}
68	        onClose={handleClose}
69	        TransitionProps={{ onExited: handleExited }}
70	        anchorOrigin={{ vertical: 'bottom', horizontal: 'center' }}
71	      >
72	        <Alert
73	          onClose={() => setOpen(false)}
74	          severity={current?.severity ?? 'info'}
75	          variant="filled"
76	          sx={{ width: '100%', minWidth: 280 }}
77	        >
78	          {current?.message}
79	        </Alert>
80	      </Snackbar>
81	    </NotifyContext.Provider>
82	  );
83	}
84	
85	export function useNotify(): NotifyFn {
86	  const ctx = useContext(NotifyContext);
87	  if (!ctx) throw new Error('useNotify must be used within NotificationsProvider');
88	  return ctx;
89	}
