1	import { createContext, useContext, useEffect, useMemo, useState, type ReactNode } from 'react';
2	
3	interface OfflineStatusValue {
4	  isOnline: boolean;
5	  isOffline: boolean;
6	  lastSyncAt: number | null;
7	}
8	
9	const OfflineStatusContext = createContext<OfflineStatusValue | null>(null);
10	
11	export const OFFLINE_MUTATION_MESSAGE = 'Reconnect to make changes.';
12	
13	interface OfflineStatusProviderProps {
14	  children: ReactNode;
15	  lastSyncAt: number | null;
16	}
17	
18	export function OfflineStatusProvider({ children, lastSyncAt }: OfflineStatusProviderProps) {
19	  const [isOnline, setIsOnline] = useState(() => navigator.onLine);
20	
21	  useEffect(() => {
22	    const handleOnline = () => setIsOnline(true);
23	    const handleOffline = () => setIsOnline(false);
24	
25	    window.addEventListener('online', handleOnline);
26	    window.addEventListener('offline', handleOffline);
27	
28	    return () => {
29	      window.removeEventListener('online', handleOnline);
30	      window.removeEventListener('offline', handleOffline);
31	    };
32	  }, []);
33	
34	  const value = useMemo<OfflineStatusValue>(() => ({
35	    isOnline,
36	    isOffline: !isOnline,
37	    lastSyncAt,
38	  }), [isOnline, lastSyncAt]);
39	
40	  return (
41	    <OfflineStatusContext.Provider value={value}>
42	      {children}
43	    </OfflineStatusContext.Provider>
44	  );
45	}
46	
47	export function useOfflineStatus(): OfflineStatusValue {
48	  const context = useContext(OfflineStatusContext);
49	  if (!context) {
50	    throw new Error('useOfflineStatus must be used within an OfflineStatusProvider');
51	  }
52	  return context;
53	}
