114	function createBatchRow(defaultItemID = ''): BatchEditDraftRow {
115	  return {
116	    id: `${Date.now()}-${Math.random().toString(36).slice(2)}`,
117	    item_id: defaultItemID,
118	    field: 'unit_price',
119	    new_value: '',
120	    availability_windows: [],
121	    client_error: null,
122	    result: null,
123	  };
124	}
