126	function toBatchEditPayload(rows: BatchEditDraftRow[]): BatchEditRequestRow[] {
127	  return rows.map((row) =>
128	    row.field === 'availability_windows'
129	      ? {
130	          item_id: row.item_id,
131	          field: row.field,
132	          availability_windows: row.availability_windows.map((window) => ({
133	            start_time: new Date(window.start_time).toISOString(),
134	            end_time: new Date(window.end_time).toISOString(),
135	          })),
136	        }
137	      : {
138	          item_id: row.item_id,
139	          field: row.field,
140	          new_value: row.new_value.trim(),
141	        },
142	  );
143	}
144	
145	function batchRowValidationMessage(row: BatchEditDraftRow): string | null {
146	  if (!row.item_id) {
147	    return 'Select an item for this row.';
148	  }
149	
150	  if (row.field === 'availability_windows') {
151	    for (const [index, window] of row.availability_windows.entries()) {
152	      if (!window.start_time || !window.end_time) {
153	        return `Availability window ${index + 1} needs both start and end times.`;
154	      }
155	      if (new Date(window.end_time) <= new Date(window.start_time)) {
156	        return `Availability window ${index + 1} must end after it starts.`;
157	      }
158	    }
159	    return null;
160	  }
161	
162	  if (!row.new_value.trim()) {
163	    return 'Enter a value for this batch edit row.';
164	  }
165	
166	  if (row.field === 'quantity') {
167	    const quantity = Number(row.new_value);
168	    if (!Number.isInteger(quantity) || quantity < 0) {
169	      return 'Quantity must be a non-negative whole number.';
170	    }
171	  }
172	
173	  if (row.field === 'unit_price' || row.field === 'refundable_deposit') {
174	    const amount = Number(row.new_value);
175	    if (Number.isNaN(amount) || amount < 0) {
176	      return 'Amounts must be non-negative numbers.';
177	    }
178	  }
179	
180	  return null;
181	}
182	
183	function rowSuccessMessage(field: BatchEditableField): string {
184	  switch (field) {
185	    case 'availability_windows':
186	      return 'Availability windows updated.';
187	    case 'refundable_deposit':
188	      return 'Refundable deposit updated.';
189	    case 'quantity':
190	      return 'Quantity updated.';
191	    default:
192	      return 'Price updated.';
193	  }
194	}
