203	  onClose: () => void;
204	  items: Item[];
205	  isOffline: boolean;
206	}) {
207	  const notify = useNotify();
208	  const batchEditMutation = useBatchEdit();
209	  const [rows, setRows] = useState<BatchEditDraftRow[]>([]);
210	
211	  useEffect(() => {
212	    if (!open) {
213	      return;
214	    }
215	    setRows((prev) => (prev.length > 0 ? prev : [createBatchRow(items[0]?.id ?? '')]));
216	  }, [open, items]);
