228	  }, []);
229	
230	  const resetAndClose = useCallback(() => {
231	    setRows([]);
232	    onClose();
233	  }, [onClose]);
234	
235	  const applyBatchResults = useCallback((response: BatchEditResponse, sourceRows: BatchEditDraftRow[]) => {
236	    setRows(sourceRows.map((row, index) => {
237	      const result = response.results[index];
238	      if (!result) {
239	        return {
240	          ...row,
241	          result: { success: false, message: 'No response returned for this row.' },
242	        };
243	      }
244	
245	      return {
246	        ...row,
247	        result: {
248	          success: result.success,
249	          message: result.success ? rowSuccessMessage(row.field) : (result.failure_reason ?? 'This row failed to update.'),
250	        },
251	      };
252	    }));
253	  }, []);
