274	        resetAndClose();
275	        return;
276	      }
277	
278	      notify.warning(`${response.success_count} row${response.success_count === 1 ? '' : 's'} succeeded and ${response.failure_count} failed.`);
279	    } catch {
280	      notify.error('Failed to apply batch edits.');
281	    }
282	  };
