201	export async function markOfflineMutationFailed(
202	  id: string,
203	  message: string,
204	): Promise<void> {
205	  if (typeof window === "undefined" || !("indexedDB" in window)) {
206	    return;
207	  }
208	
209	  const existing = await loadPendingOfflineMutations();
210	  const now = Date.now();
211	  const queue: PersistedMutationQueue = {
212	    version: MUTATION_QUEUE_VERSION,
213	    updatedAt: now,
214	    mutations: existing.map((entry) => {
215	      if (entry.id !== id) {
216	        return entry;
217	      }
218	      return {
219	        ...entry,
220	        status: "failed",
221	        updatedAt: now,
222	        lastError: message,
223	      };
224	    }),
225	  };
226	  await writeStoreValue(MUTATION_QUEUE_KEY, queue);
227	}
