229	export async function removeOfflineMutation(id: string): Promise<void> {
230	  if (typeof window === "undefined" || !("indexedDB" in window)) {
231	    return;
232	  }
233	
234	  const existing = await loadPendingOfflineMutations();
235	  const queue: PersistedMutationQueue = {
236	    version: MUTATION_QUEUE_VERSION,
237	    updatedAt: Date.now(),
238	    mutations: existing.filter((entry) => entry.id !== id),
239	  };
240	  await writeStoreValue(MUTATION_QUEUE_KEY, queue);
241	}
