88	      if (typeof navigator !== "undefined" && !navigator.onLine) {
89	        await enqueueOfflineMutation({
90	          id: globalThis.crypto?.randomUUID?.() ?? `${Date.now()}-update-item`,
91	          type: "update-item",
92	          payload: { id, body },
93	          createdAt: Date.now(),
94	        });
95	        return { id, ...(body as Record<string, unknown>) } as Item;
96	      }
97	      const response = await apiClient.put<ApiEnvelope<Item>>(
98	        `/items/${id}`,
99	        body,
100	      );
101	      return response.data;
102	    },
103	    onSuccess: (_, { id }) => {
104	      qc.invalidateQueries({ queryKey: ["items"] });
105	      qc.invalidateQueries({ queryKey: ["items", id] });
106	    },
