60	  queryClient: QueryClient,
61	): Promise<number> {
62	  if (isBrowserOffline()) {
63	    return 0;
64	  }
65	
66	  const queue = await loadPendingOfflineMutations();
67	  let processed = 0;
68	
69	  for (const entry of queue) {
70	    if (entry.status === "failed") {
71	      continue;
72	    }
73	
74	    try {
75	      await executeMutation(entry);
76	      await removeOfflineMutation(entry.id);
77	      processed += 1;
78	    } catch (error) {
79	      if (isOfflineApiError(error)) {
80	        break;
81	      }
82	
83	      const message =
84	        typeof error === "object" && error && "message" in error
85	          ? String((error as { message?: unknown }).message ?? "replay failed")
86	          : "replay failed";
87	      await markOfflineMutationFailed(entry.id, message);
88	    }
89	  }
90	
91	  if (processed > 0) {
92	    queryClient.invalidateQueries({ queryKey: ["items"] });
93	    queryClient.invalidateQueries({ queryKey: ["reports"] });
94	    queryClient.invalidateQueries({ queryKey: ["exports"] });
95	  }
96	
97	  return processed;
98	}
