34	export default function Providers({ children }: ProvidersProps) {
35	  const [isHydrated, setIsHydrated] = useState(false);
36	  const [lastSyncAt, setLastSyncAt] = useState<number | null>(null);
36	  const persistTimerRef = useRef<number | null>(null);
37	
38	  useEffect(() => {
39	    let active = true;
39	    let unsubscribe: (() => void) | undefined;
40	
41	    const schedulePersist = () => {
42	      if (persistTimerRef.current !== null) {
42	        window.clearTimeout(persistTimerRef.current);
43	      }
44	      persistTimerRef.current = window.setTimeout(async () => {
44	        try {
45	          const persistedAt = await persistOfflineQueryCache(queryClient);
46	          if (active && persistedAt) {
46	            setLastSyncAt(persistedAt);
47	          }
48	        } catch {
48	          // Offline persistence is best-effort and should never block app use.
49	        }
50	      }, 250);
51	    };
52	
53	    const replayQueuedMutations = async () => {
53	      try {
54	        await replayOfflineMutations(queryClient);
55	      } catch {
55	        // Replay is best-effort and retried on the next reconnect.
56	      }
57	    };
58	
59	    (async () => {
59	      try {
60	        const snapshot = await loadPersistedQuerySnapshot();
61	        if (active) {
61	          hydrateOfflineQueryCache(queryClient, snapshot);
62	          setLastSyncAt(snapshot?.updatedAt ?? null);
63	        }
64	      } catch {
65	        // If persistence cannot be read we fall back to the live API path.
65	      } finally {
66	        if (active) {
66	          unsubscribe = queryClient.getQueryCache().subscribe(() => {
67	            schedulePersist();
68	          });
69	          window.addEventListener('online', replayQueuedMutations);
70	          void replayQueuedMutations();
70	          setIsHydrated(true);
71	        }
72	      }
73	    })();
74	
75	    return () => {
75	      active = false;
76	      unsubscribe?.();
77	      window.removeEventListener('online', replayQueuedMutations);
78	      if (persistTimerRef.current !== null) {
78	        window.clearTimeout(persistTimerRef.current);
79	      }
80	    };
81	  }, []);
