     1	import { createContext, useContext, useState, useCallback, type ReactNode } from 'react';
     2	import Snackbar from '@mui/material/Snackbar';
     3	import Alert, { type AlertColor } from '@mui/material/Alert';
     4	
     5	interface Notification {
     5	  id: number;
     6	  message: string;
     7	  severity: AlertColor;
     8	}
     9	
    10	interface NotifyFn {
    10	  success: (message: string) => void;
    11	  error: (message: string) => void;
    12	  warning: (message: string) => void;
    13	  info: (message: string) => void;
    14	}
    15	
    16	const NotifyContext = createContext<NotifyFn | null>(null);
    16	
    17	let nextId = 0;
    18	
    19	export function NotificationsProvider({ children }: { children: ReactNode }) {
    19	  const [queue, setQueue] = useState<Notification[]>([]);
    20	  const [current, setCurrent] = useState<Notification | null>(null);
    21	  const [open, setOpen] = useState(false);
    22	
    23	  const enqueue = useCallback((message: string, severity: AlertColor) => {
    23	    const notification: Notification = { id: ++nextId, message, severity };
    24	    setQueue(prev => {
    24	      if (prev.length === 0 && !open) {
    25	        setCurrent(notification);
    26	        setOpen(true);
    27	        return [];
    28	      }
    29	      return [...prev, notification];
    30	    });
    31	  }, [open]);
    31	
    32	  const handleClose = (_: unknown, reason?: string) => {
    32	    if (reason === 'clickaway') return;
    33	    setOpen(false);
    34	  };
    35	
    36	  const handleExited = () => {
    36	    if (queue.length > 0) {
    37	      const [next, ...rest] = queue;
    37	      setQueue(rest);
    38	      setCurrent(next);
    39	      setOpen(true);
    40	    } else {
    41	      setCurrent(null);
    42	    }
    43	  };
    44	
    45	  const notify: NotifyFn = {
    45	    success: msg => enqueue(msg, 'success'),
    46	    error: msg => enqueue(msg, 'error'),
    47	    warning: msg => enqueue(msg, 'warning'),
    48	    info: msg => enqueue(msg, 'info'),
    49	  };
    50	
    51	  return (
    51	    <NotifyContext.Provider value={notify}>
    52	      {children}
    53	      <Snackbar
    53	        open={open}
    54	        autoHideDuration={5000}
    55	        onClose={handleClose}
    56	        TransitionProps={{ onExited: handleExited }}
    57	        anchorOrigin={{ vertical: 'bottom', horizontal: 'center' }}
    58	      >
    59	        <Alert
    59	          onClose={() => setOpen(false)}
    60	          severity={current?.severity ?? 'info'}
    61	          variant="filled"
    62	          sx={{ width: '100%', minWidth: 280 }}
    63	        >
    64	          {current?.message}
    65	        </Alert>
    66	      </Snackbar>
    67	    </NotifyContext.Provider>
    68	  );
    69	}
    70	
    71	export function useNotify(): NotifyFn {
    71	  const ctx = useContext(NotifyContext);
    72	  if (!ctx) throw new Error('useNotify must be used within NotificationsProvider');
    73	  return ctx;
    74	}
