    19	export function NotificationsProvider({ children }: { children: ReactNode }) {
    19	  const [queue, setQueue] = useState<Notification[]>([]);
    20	  const [current, setCurrent] = useState<Notification | null>(null);
    21	  const [open, setOpen] = useState(false);
    22	
    23	  const enqueue = useCallback((message: string, severity: AlertColor) => {
    23	    const notification: Notification = { id: ++nextId, message, severity };
    24	    setQueue(prev => {
    24	      if (prev.length === 0 && !open) {
    25	        setCurrent(notification);
    26	        setOpen(true);
    27	        return [];
    28	      }
    29	      return [...prev, notification];
    30	    });
    31	  }, [open]);
    31	
    32	  const handleClose = (_: unknown, reason?: string) => {
    32	    if (reason === 'clickaway') return;
    33	    setOpen(false);
    34	  };
    35	
    36	  const handleExited = () => {
    36	    if (queue.length > 0) {
    37	      const [next, ...rest] = queue;
    37	      setQueue(rest);
    38	      setCurrent(next);
    39	      setOpen(true);
    40	    } else {
    41	      setCurrent(null);
    42	    }
    43	  };
    44	
    45	  const notify: NotifyFn = {
    45	    success: msg => enqueue(msg, 'success'),
    46	    error: msg => enqueue(msg, 'error'),
    47	    warning: msg => enqueue(msg, 'warning'),
    48	    info: msg => enqueue(msg, 'info'),
    49	  };
    50	
    51	  return (
    51	    <NotifyContext.Provider value={notify}>
    52	      {children}
    53	      <Snackbar
    53	        open={open}
    54	        autoHideDuration={5000}
    55	        onClose={handleClose}
    56	        TransitionProps={{ onExited: handleExited }}
    57	        anchorOrigin={{ vertical: 'bottom', horizontal: 'center' }}
    58	      >
